function findSeoulGu(slug) {
  return SEOUL_GUS.find(g => g.slug === slug);
}
function findSeoulDong(guSlug, dongSlug) {
  const gu = findSeoulGu(guSlug);
  if (!gu) return null;
  const d = gu.dongs.find(x => x.slug === dongSlug);
  return d ? { ...d, gu } : null;
}

