// 헬퍼: 시군구 찾기 (서울 외 16개 광역시도)
function findRegionGu(sidoSlug, guSlug) {
  const gus = REGIONS_DATA[sidoSlug];
  if (!gus) return null;
  const g = gus.find(g => g.slug === guSlug);
  if (!g) return null;
  return { ...g, sidoSlug };
}

// 헬퍼: 읍면동 찾기 (서울 외 16개 광역시도)
function findRegionDong(sidoSlug, guSlug, dongSlug) {
  const gu = findRegionGu(sidoSlug, guSlug);
  if (!gu) return null;
  const dong = gu.dongs.find(d => d.slug === dongSlug);
  if (!dong) return null;
  return { ...dong, gu, sidoSlug };
}



