// 풀에서 N개 선택 (해시 기반 결정론적)
function _dongPick(salt, pool, n) {
  const h = _seoulHash(salt);
  const indices = [];
  // 간단한 결정론적 랜덤 선택
  const copy = [...pool];
  for (let i = 0; i < n && copy.length > 0; i++) {
    const idx = _seoulHash(salt + '-' + i) % copy.length;
    indices.push(copy[idx]);
    copy.splice(idx, 1);
  }
  return indices;
}

// ========== 서울 동 페이지 ==========
