  sidoSlug = sidoSlug || 'seoul';
  regionName = regionName || '서울';
  const regionFullName = sidoSlug === 'seoul' ? '서울특별시' : regionName;
  const gu = dong.gu;
  const name = dong.name;
  const parent = gu.name;
