function renderSigunguPage(sg) {
  const region = findRegion(sg.sidoSlug);

  // 상권 블록 (5개)
  const commercialBlocks = sg.commercialAreas.map((c, i) => `
<div class="sg-commercial-card">
  <div class="sg-commercial-num">${String(i + 1).padStart(2, '0')}</div>
  <h3>${c.name}</h3>
  <p class="sg-commercial-trait">${c.trait}</p>
  <p class="sg-commercial-rec"><strong>추천:</strong> ${c.recommend}</p>
</div>`).join('');

  // 업종별 블록 (5개)
  const industryBlocks = sg.industries.map((ind, i) => `
<div class="sg-industry-row">
  <div class="sg-industry-head">
    <span class="sg-industry-tag">${ind.weight}</span>
    <h4>${ind.name}</h4>
  </div>
  <p>${ind.detail}</p>
</div>`).join('');

  // 제품별 짧은 안내 (7개)
  const productBlocks = PRODUCTS.map(p => {
    const imgSrc = PRODUCT_IMAGES[p.slug];
    const thumb = imgSrc ? `<img src="${imgSrc}" alt="${p.name}" loading="lazy">` : p.emoji;
    return `<a href="/product/${p.slug}" class="sgu-prod sgu-prod-img"><div class="sgu-prod-ic">${thumb}</div><div class="sgu-prod-name">${p.name}</div></a>`;
  }).join('');

  // FAQ
  const faqBlocks = sg.faqs.map(f => `
<div class="sg-faq-item">
  <div class="sg-faq-q"><strong>Q.</strong> ${f.q}</div>
  <div class="sg-faq-a">${f.a}</div>
</div>`).join('');

  // 태그 10개
  const tagBlocks = sg.tags.map(t => `<span class="sg-tag">#${t}</span>`).join('');

  // 관련 지역 (나중에 시군구 추가되면 연결됨, 지금은 광역도 + 인근 시군구 링크)
  const relatedCards = [
    { href: `/region/${sg.sidoSlug}`, title: `${sg.sido} 전체`, sub: '광역시도 랜딩' },
    { href: '/region/gyeonggi', title: '경기 설치', sub: '경기도 31개 시군' },
    { href: '/region/incheon', title: '인천 설치', sub: '인천 10개 군구' },
    { href: '/region', title: '전체 지역', sub: '전국 17개 광역' },
  ].map(r => `<a href="${r.href}" class="sg-related-card"><h5>${r.title}</h5><span>${r.sub}</span></a>`).join('');

  // 사이드바 다른 지역
  const otherRegions = REGIONS.slice(0, 7)
    .filter(r => r.slug !== sg.sidoSlug)
    .slice(0, 5)
    .map(r => `<li><a href="/region/${r.slug}">${r.name}</a></li>`).join('');

  // 사이드바 제품별
  const sideProducts = PRODUCTS.map(p => `<li><a href="/product/${p.slug}">${p.emoji} ${sg.name} ${p.name}</a></li>`).join('');

  const body = `
<section class="sg-hero">
  <div class="container">
    <div class="breadcrumb">
      <a href="/">홈</a><span class="sep">›</span>
      <a href="/region">지역별 설치</a><span class="sep">›</span>
      <a href="/region/${sg.sidoSlug}">${sg.sido}</a><span class="sep">›</span>
      ${sg.name}
    </div>
    <div class="sg-hero-thumb">
      <div class="sg-hero-img" style="background-image:url('${HERO_BANNER_INSTALL || ''}');"></div>
      <div class="sg-hero-overlay">
        <div class="sg-hero-meta">${sg.fullName} · ${sg.dongCount}개 동</div>
        <div class="sg-hero-title">${sg.name} 설치 전문</div>
        <div class="sg-hero-sub">카드단말기 · 포스기 · 키오스크 · CCTV · 테이블오더 · 철거</div>
      </div>
    </div>
    <h1 class="sg-h1">${sg.name} 카드단말기·포스기·키오스크 설치</h1>
    <p class="sg-lead">${sg.fullName} 전 지역 당일·익일 출장 설치. ${sg.name} 월 평균 <strong>${sg.monthlyInstalls}+건</strong>의 설치를 진행하고 있습니다.</p>
  </div>
</section>

<section class="sg-main">
  <div class="container sg-layout">
    <aside class="sg-sidebar">
      <div class="sg-side-card">
        <h4>📍 다른 지역</h4>
        <ul>${otherRegions}</ul>
      </div>
      <div class="sg-side-card">
        <h4>🛒 ${sg.name} 제품별</h4>
        <ul>${sideProducts}</ul>
      </div>
      <div class="sg-side-card sg-side-cta">
        <h4>📞 무료 상담</h4>
        <p>${sg.name} 전 지역 출장</p>
        <a href="tel:${SITE.phone}" class="sg-side-tel">${SITE.phoneDisplay}</a>
        <a href="/contact" class="sg-side-btn">상담 문의 →</a>
      </div>
    </aside>

    <article class="sg-article">

      <section class="sg-block">
        <h2>📍 ${sg.name} 상권 특성</h2>
        <p>${sg.fullName}은(는) 인구 ${sg.population}명, 면적 ${sg.area} 규모의 ${sg.dongCount}개 법정동으로 구성된 지역입니다. ${sg.landmarks.slice(0, 4).join(', ')} 등의 주요 랜드마크를 중심으로 서로 다른 성격의 상권이 형성되어 있습니다.</p>
        <p>${sg.localInsight}</p>
        <div class="sg-stats">
          <div class="sg-stat"><div class="sg-stat-n">${sg.monthlyInstalls}+</div><div class="sg-stat-l">월 설치 건수</div></div>
          <div class="sg-stat"><div class="sg-stat-n">${sg.dongCount}</div><div class="sg-stat-l">커버 동 수</div></div>
          <div class="sg-stat"><div class="sg-stat-n">당일</div><div class="sg-stat-l">평균 설치</div></div>
          <div class="sg-stat"><div class="sg-stat-n">무료</div><div class="sg-stat-l">출장·견적</div></div>
        </div>
      </section>

      <section class="sg-block">
        <h2>🏙️ ${sg.name} 주요 상권별 설치 가이드</h2>
        <p>${sg.name} 안에서도 동(洞)·상권별로 주력 업종과 필요한 설비가 다릅니다. 아래는 ${sg.name}의 5대 상권별 특성과 추천 설비입니다.</p>
        <div class="sg-commercial-grid">${commercialBlocks}</div>
      </section>

      <section class="sg-block">
        <h2>🏢 ${sg.name} 업종별 설치 특성</h2>
        <p>${sg.name} 상권에서 특히 수요가 많은 5대 업종과 각 업종에 맞는 설비 조합을 안내드립니다.</p>
        <div class="sg-industry-list">${industryBlocks}</div>
      </section>

      <section class="sg-block sg-trend">
        <h2>📈 ${sg.name} 최근 트렌드</h2>
        <p>${sg.recentTrend}</p>
      </section>

      <section class="sg-block sg-tip">
        <div class="sg-tip-head">💡 ${sg.name} 사장님 Tip</div>
        <p>${sg.specialTip}</p>
      </section>

      <section class="sg-block">
        <h2>🛒 ${sg.name} 제품별 설치 안내</h2>
        <div class="sgu-prod-grid">${productBlocks}</div>
      </section>

      <section class="sg-block">
        <h2>❓ ${sg.name} 설치 자주 묻는 질문</h2>
        <div class="sg-faq-list">${faqBlocks}</div>
      </section>

      <section class="sg-block sg-tags">
        <h2>🏷️ 관련 태그</h2>
        <div class="sg-tag-list">${tagBlocks}</div>
      </section>

      <section class="sg-block">
        <h2>🔗 관련 지역 설치 안내</h2>
        <div class="sg-related-grid">${relatedCards}</div>
      </section>

      <section class="sg-block sg-bottom-cta">
        <h2>📞 ${sg.name} 무료 견적 받기</h2>
        <p>${sg.name} 전 지역 당일·익일 출장 설치. 전화 한 통이면 매장에 맞는 장비를 추천해드립니다.</p>
        <div class="sg-cta-buttons">
          <a href="tel:${SITE.phone}" class="btn btn-primary">📞 ${SITE.phoneDisplay}</a>
          <a href="/contact" class="btn btn-ghost">💬 상담 문의</a>
        </div>
      </section>

    </article>
  </div>
</section>`;

  const opts = {
    title: `${sg.metaTitle} | ${SITE.brandNameKo}`,
    description: sg.metaDesc,
    keywords: sg.tags.join(', '),
    canonical: `${SITE.domain}/region/${sg.sidoSlug}/${sg.slug}`,
  };
  return htmlWrap({ ...opts, body });
}

function renderRegionIndex() {
  const cards = REGIONS.map(r => `<a href="/region/${r.slug}" class="index-card"><div class="big">${r.emoji}</div><h3>${r.name}</h3><p>${r.coverage} · ${r.installTime}</p></a>`).join('');
  const body = `
<section class="index-header">
<div class="container">
<div class="breadcrumb"><a href="/">홈</a><span class="sep">›</span>지역별 설치</div>
<h1><em>전국 17개</em> 광역시도 설치</h1>
<p>서울부터 제주까지 전국 어디서든 ${SITE.brandNameKo}가 찾아갑니다. 지역을 선택하면 해당 지역의 상권 정보와 제품별 설치 가이드를 확인할 수 있습니다.</p>
</div>
</section>
<section class="container">
<div class="index-grid cols-4">${cards}</div>
</section>
`;
  return htmlWrap({
    title: '지역별 설치 · 전국 17개 광역시도',
    description: '전국 17개 광역시도 매장 설비 설치. 서울·경기·부산·대구 등 원하는 지역을 선택하세요.',
    canonical: `${SITE.domain}/region`,
    body,
  });
}

