// 데이터 조회 헬퍼
function findRegion(slug) { return REGIONS.find(r => r.slug === slug); }
function findProduct(slug) { return PRODUCTS.find(p => p.slug === slug); }
function findSigungu(sidoSlug, slug) {
  return SIGUNGU_DETAILS.find(s => s.sidoSlug === sidoSlug && s.slug === slug);
}

// [16] fetch 라우터 (핵심) ====================================
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    let pathname = url.pathname;
    // Normalize: trailing slash 제거 (/ 자체는 유지)
    if (pathname.length > 1 && pathname.endsWith('/')) {
      pathname = pathname.slice(0, -1);
    }
    const htmlHeaders = { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'public,max-age=3600' };

    // 메인 페이지
    if (pathname === '/' || pathname === '') {
      return new Response(renderHome(), { headers: htmlHeaders });
    }

    // sitemap.xml
    if (pathname === '/sitemap.xml' || pathname === '/sitemap-index.xml') {
      return new Response(renderSitemap(), {
        headers: { 'Content-Type': 'application/xml; charset=utf-8', 'Cache-Control': 'public,max-age=3600' }
      });
    }

    // robots.txt
    if (pathname === '/robots.txt') {
      return new Response(renderRobots(), {
        headers: { 'Content-Type': 'text/plain; charset=utf-8', 'Cache-Control': 'public,max-age=86400' }
      });
    }

    // favicon.svg — 브라우저 탭 아이콘 (네이비 + 주황 그리드)
    if (pathname === '/favicon.svg' || pathname === '/favicon.ico' || pathname === '/favicon.png' || pathname === '/apple-touch-icon.png') {
      return new Response(renderFavicon(), {
        headers: { 'Content-Type': 'image/svg+xml; charset=utf-8', 'Cache-Control': 'public,max-age=604800' }
      });
    }

    // 지역 인덱스
    if (pathname === '/region') {
      return new Response(renderRegionIndex(), { headers: htmlHeaders });
    }

    // 제품 인덱스
    if (pathname === '/product') {
      return new Response(renderProductIndex(), { headers: htmlHeaders });
    }

    // 업종별 인덱스
    if (pathname === '/industry') {
      return new Response(renderIndustryIndex(), { headers: htmlHeaders });
    }

    // 업종별 상세 /industry/{slug}
    const industryMatch = pathname.match(/^\/industry\/([a-z-]+)$/);
    if (industryMatch) {
      const industry = findIndustry(industryMatch[1]);
      if (industry) return new Response(renderIndustryPage(industry), { headers: htmlHeaders });
    }

    // 상담 문의 페이지
    if (pathname === '/contact') {
      return new Response(renderContactPage(), { headers: htmlHeaders });
    }

    // 상담 문의 폼 제출 (POST)
    if (pathname === '/contact/submit' && request.method === 'POST') {
      return handleContactSubmit(request, env);
    }

    // 지역×시군구 상세 /region/{sidoSlug}/{slug} — 반드시 단일 패턴보다 먼저!
    // [동×제품] 페이지: /region/{sido}/{gu}/{dong}/{product} — 4 segment, 가장 먼저 매칭
    // [서울] 동 × 제품: /region/seoul/{gu}/{dong}/{product}
    const seoulDongProdMatch = pathname.match(/^\/region\/seoul\/([a-z0-9-]+)\/([a-z0-9-]+)\/([a-z-]+)$/);
    if (seoulDongProdMatch) {
      const dong = findSeoulDong(seoulDongProdMatch[1], seoulDongProdMatch[2]);
      const product = findProduct(seoulDongProdMatch[3]);
      if (dong && product) return new Response(renderDongProductPage(dong, 'seoul', '서울', product), { headers: htmlHeaders });
    }
    // [서울 외 16개 광역시도] 동 × 제품: /region/{sido}/{gu}/{dong}/{product}
    const regionDongProdMatch = pathname.match(/^\/region\/([a-z-]+)\/([a-z0-9-]+)\/([a-z0-9-]+)\/([a-z-]+)$/);
    if (regionDongProdMatch) {
      const dong = findRegionDong(regionDongProdMatch[1], regionDongProdMatch[2], regionDongProdMatch[3]);
      const product = findProduct(regionDongProdMatch[4]);
      if (dong && product) {
        const region = findRegion(regionDongProdMatch[1]);
        if (region) {
          const html = renderDongProductPage(dong, regionDongProdMatch[1], region.name, product);
          if (html) return new Response(html, { headers: htmlHeaders });
        }
      }
    }
    // [서울] /region/seoul/{gu}/{X} — X가 product slug면 시군구×제품, 아니면 dong
    const seoulDongMatch = pathname.match(/^\/region\/seoul\/([a-z0-9-]+)\/([a-z0-9-]+)$/);
    if (seoulDongMatch) {
      const guSlug = seoulDongMatch[1], thirdSeg = seoulDongMatch[2];
      // product slug 우선 검사
      const product = findProduct(thirdSeg);
      if (product) {
        const gu = findSeoulGu(guSlug);
        if (gu) return new Response(renderSigunguProductPage(gu, 'seoul', '서울', product), { headers: htmlHeaders });
      }
      const dong = findSeoulDong(guSlug, thirdSeg);
      if (dong) return new Response(renderSeoulDongPage(dong), { headers: htmlHeaders });
    }
    // [서울] 구 페이지: /region/seoul/{gu}
    const seoulGuMatch = pathname.match(/^\/region\/seoul\/([a-z0-9-]+)$/);
    if (seoulGuMatch) {
      const gu = findSeoulGu(seoulGuMatch[1]);
      if (gu) return new Response(renderSeoulGuPage(gu), { headers: htmlHeaders });
    }
    // [서울 외] /region/{sido}/{gu}/{X} — X가 product slug면 시군구×제품, 아니면 dong
    const regionDongMatch = pathname.match(/^\/region\/([a-z-]+)\/([a-z0-9-]+)\/([a-z0-9-]+)$/);
    if (regionDongMatch) {
      const sidoSlug = regionDongMatch[1], guSlug = regionDongMatch[2], thirdSeg = regionDongMatch[3];
      const region = findRegion(sidoSlug);
      // product slug 우선 검사
      const product = findProduct(thirdSeg);
      if (product && region) {
        const gu = findRegionGu(sidoSlug, guSlug);
        if (gu) return new Response(renderSigunguProductPage(gu, sidoSlug, region.name, product), { headers: htmlHeaders });
      }
      const dong = findRegionDong(sidoSlug, guSlug, thirdSeg);
      if (dong && region) {
        const html = renderSeoulDongPage(dong, sidoSlug, region.name);
        if (html) return new Response(html, { headers: htmlHeaders });
      }
    }
    // [서울 외] 시 페이지 (수원시·성남시 등): /region/{sido}/{city}
    const subcityMatch = pathname.match(/^\/region\/([a-z-]+)\/([a-z0-9-]+)$/);
    if (subcityMatch) {
      const city = findSubcity(subcityMatch[1], subcityMatch[2]);
      if (city) {
        const html = renderSubcityPage(city);
        if (html) return new Response(html, { headers: htmlHeaders });
      }
    }
    // [서울 외 16개 광역시도] 구 페이지: /region/{sido}/{gu}
    const regionGuMatch = pathname.match(/^\/region\/([a-z-]+)\/([a-z0-9-]+)$/);
    if (regionGuMatch) {
      const gu = findRegionGu(regionGuMatch[1], regionGuMatch[2]);
      if (gu) {
        const region = findRegion(regionGuMatch[1]);
        if (region) {
          const html = renderSeoulGuPage(gu, regionGuMatch[1], region.name);
          if (html) return new Response(html, { headers: htmlHeaders });
        }
      }
    }
    const sigunguMatch = pathname.match(/^\/region\/([a-z-]+)\/([a-z-]+)$/);
    if (sigunguMatch) {
      const sg = findSigungu(sigunguMatch[1], sigunguMatch[2]);
      if (sg) return new Response(renderSigunguPage(sg), { headers: htmlHeaders });
    }

    // 지역 상세 /region/{slug}
    const regionMatch = pathname.match(/^\/region\/([a-z-]+)$/);
    if (regionMatch) {
      const region = findRegion(regionMatch[1]);
      if (region) return new Response(renderRegionPage(region), { headers: htmlHeaders });
    }

    // 제품 상세 /product/{slug}
    const productMatch = pathname.match(/^\/product\/([a-z-]+)$/);
    if (productMatch) {
      const product = findProduct(productMatch[1]);
      if (product) return new Response(renderProductPage(product), { headers: htmlHeaders });
    }

    // 지역x제품 /{region}/{product}
    const installMatch = pathname.match(/^\/([a-z-]+)\/([a-z-]+)$/);
    if (installMatch) {
      const region = findRegion(installMatch[1]);
      const product = findProduct(installMatch[2]);
      if (region && product) {
        return new Response(renderInstallPage(region, product), { headers: htmlHeaders });
      }
    }

    // 404
    return new Response(render404(), { status: 404, headers: htmlHeaders });
  }
};
